insert into locations (name, city, country, type, description, price, currency, rating, reviews, area, capacity, latitude, longitude, tags, amenities, fallback, featured, trending, specs, image_urls, published) values
('Dar El Médina', 'Sidi Bou Said', 'Tunisia', 'villa', 'A whitewashed villa perched over the Gulf of Tunis, with cobalt-blue mashrabiya shutters and bougainvillea-draped terraces. The postcard Tunisia, reimagined for contemporary campaigns.', 680, '€', 4.9, 142, 320, 40, 36.8704, 10.3472, array['Photo Shoot', 'Video', 'Brand Campaigns'], array['Sea View', 'Private Terrace', 'Natural Light', 'WiFi', 'Staff on request', 'Parking'], '#102035', true, true, '{"rooms": 6, "bathrooms": 4, "ceiling": "3.2m", "power": "3x 32A", "parking": "8 vehicles"}', array['https://images.unsplash.com/photo-1548263594-a71ea65a8598?w=1800&q=85&auto=format&fit=crop', 'https://images.unsplash.com/photo-1605538032404-d7f061325e55?w=1800&q=85&auto=format&fit=crop', 'https://images.unsplash.com/photo-1583415047488-61e3d6b8c8ae?w=1800&q=85&auto=format&fit=crop', 'https://images.unsplash.com/photo-1553244572-ff51f4df4c0d?w=1800&q=85&auto=format&fit=crop'], true),
('Villa Lumière Méditerranée', 'La Marsa', 'Tunisia', 'villa', 'A minimalist seafront estate on the northern coast — polished travertine, infinity pool, and uninterrupted Mediterranean light. A canvas for luxury fashion and editorial shoots.', 1100, '€', 5.0, 58, 620, 80, 36.878, 10.3247, array['Photo Shoot', 'Events', 'Brand Campaigns'], array['Infinity Pool', 'Sea Access', 'Full Staff', 'Parking', 'WiFi', 'Catering Kitchen'], '#0e1a25', true, false, '{"rooms": 9, "bathrooms": 6, "ceiling": "3.6m", "power": "3x 63A", "parking": "15 vehicles"}', array['https://images.unsplash.com/photo-1519452575417-564c1401ecc0?w=1800&q=85&auto=format&fit=crop', 'https://images.unsplash.com/photo-1540541338287-41700207dee6?w=1800&q=85&auto=format&fit=crop', 'https://images.unsplash.com/photo-1515541324332-7dd0c37426e0?w=1800&q=85&auto=format&fit=crop', 'https://images.unsplash.com/photo-1507525428034-b723cf961d3e?w=1800&q=85&auto=format&fit=crop'], true),
('The Kairouan Quarter', 'Kairouan', 'Tunisia', 'loft', 'A restored medina palace with vaulted brick ceilings, carved cedar doors, and layered zellige tilework. The oldest Islamic city in the Maghreb as your set.', 380, '€', 4.8, 187, 410, 50, 35.6781, 10.0963, array['Film Production', 'Photo Shoot', 'Events'], array['Courtyard', 'Original Tilework', 'Generator', 'WiFi', 'Green Room'], '#2b1d10', true, true, '{"rooms": 8, "bathrooms": 3, "ceiling": "4.5m", "power": "3x 32A + generator", "parking": "12 vehicles"}', array['https://images.unsplash.com/photo-1570135463719-58a7cc8e0a55?w=1800&q=85&auto=format&fit=crop', 'https://images.unsplash.com/photo-1602066024551-8b0c2c5e0b89?w=1800&q=85&auto=format&fit=crop', 'https://images.unsplash.com/photo-1598828073074-bd1d0c8bd2c1?w=1800&q=85&auto=format&fit=crop', 'https://images.unsplash.com/photo-1558618666-fcd25c85cd64?w=1800&q=85&auto=format&fit=crop'], true),
('Rooftop Bab Bhar', 'Tunis', 'Tunisia', 'rooftop', 'A panoramic rooftop above the old city gates — minarets on one horizon, the bay on the other. Retractable canopy and bleached timber deck for golden-hour Tunis.', 290, '€', 4.7, 96, 210, 45, 36.8008, 10.1817, array['Photo Shoot', 'Events', 'Influencer'], array['360° View', 'Retractable Canopy', 'Outdoor Furniture', 'WiFi', 'Bar Setup'], '#1a1410', true, true, '{"rooms": 1, "bathrooms": 2, "ceiling": "open-air", "power": "2x 32A", "parking": "street"}', array['https://images.unsplash.com/photo-1587974928441-35e0ce9e3f49?w=1800&q=85&auto=format&fit=crop', 'https://images.unsplash.com/photo-1585468274952-66591eb14165?w=1800&q=85&auto=format&fit=crop', 'https://images.unsplash.com/photo-1568849676085-51415703900f?w=1800&q=85&auto=format&fit=crop', 'https://images.unsplash.com/photo-1519750783826-e2420f4d687f?w=1800&q=85&auto=format&fit=crop'], true),
('Studio Oasis', 'Tozeur', 'Tunisia', 'studio', 'A purpose-built sand-colored studio at the edge of the Chott el Djerid salt flats. Seamless cove, pro rigging, and a private palmeraie courtyard for natural-light work.', 520, '€', 4.9, 154, 340, 25, 33.9197, 8.1335, array['Photo Shoot', 'Video', 'Film Production'], array['Infinity Cove', 'Pro Lighting', 'Production Suite', 'WiFi', 'Makeup Station', 'AC'], '#3a2614', true, false, '{"rooms": 4, "bathrooms": 3, "ceiling": "5.8m", "power": "3x 63A + generator", "parking": "20 vehicles"}', array['https://images.unsplash.com/photo-1469854523086-cc02fe5d8800?w=1800&q=85&auto=format&fit=crop', 'https://images.unsplash.com/photo-1473580044384-7ba9967e16a0?w=1800&q=85&auto=format&fit=crop', 'https://images.unsplash.com/photo-1452022449556-ca4d63715770?w=1800&q=85&auto=format&fit=crop', 'https://images.unsplash.com/photo-1515162305285-0293e4767cc2?w=1800&q=85&auto=format&fit=crop'], true),
('Maison Troglodyte', 'Matmata', 'Tunisia', 'mansion', 'An underground Berber dwelling carved into volcanic rock, made legendary by cinema. Raw ochre walls, sculpted stone arches, and endless Saharan horizon above.', 740, '€', 4.8, 52, 480, 60, 33.5443, 9.9703, array['Film Production', 'Photo Shoot', 'Brand Campaigns'], array['Historic Set', 'Desert Access', 'Full Kitchen', 'Generator', 'Parking 20+'], '#2a1810', true, false, '{"rooms": 12, "bathrooms": 4, "ceiling": "3.0m", "power": "generator", "parking": "25 vehicles"}', array['https://images.unsplash.com/photo-1527004760525-c9f8b0eaac8a?w=1800&q=85&auto=format&fit=crop', 'https://images.unsplash.com/photo-1519046904884-53103b34b206?w=1800&q=85&auto=format&fit=crop', 'https://images.unsplash.com/photo-1506259091721-347e791bab0f?w=1800&q=85&auto=format&fit=crop', 'https://images.unsplash.com/photo-1523496922380-91d5afba98a3?w=1800&q=85&auto=format&fit=crop'], true),
('Dar Djerba', 'Djerba', 'Tunisia', 'penthouse', 'A whitewashed island menzel with domed roofs and a courtyard pool ringed by olive trees. Calm Mediterranean light all year — the Cyclades of North Africa.', 640, '€', 5.0, 41, 260, 22, 33.8076, 10.8451, array['Photo Shoot', 'Video', 'Events'], array['Courtyard Pool', 'Island View', 'Private Access', 'WiFi', 'Olive Grove'], '#0a1f2e', true, true, '{"rooms": 5, "bathrooms": 3, "ceiling": "3.4m", "power": "3x 32A", "parking": "6 vehicles"}', array['https://images.unsplash.com/photo-1507525428034-b723cf961d3e?w=1800&q=85&auto=format&fit=crop', 'https://images.unsplash.com/photo-1505873242700-f289a29e1e0f?w=1800&q=85&auto=format&fit=crop', 'https://images.unsplash.com/photo-1533106418989-88406c7cc8ca?w=1800&q=85&auto=format&fit=crop', 'https://images.unsplash.com/photo-1523712999610-f77fbcfc3843?w=1800&q=85&auto=format&fit=crop'], true),
('Desert Cube Tataouine', 'Tataouine', 'Tunisia', 'villa', 'A minimalist concrete cube rising from the red dunes south of Tataouine. Private plunge pool, ksar-style courtyards, interiors blending Berber craft with Bauhaus precision.', 560, '€', 4.9, 88, 420, 35, 32.9297, 10.4518, array['Film Production', 'Photo Shoot', 'Influencer'], array['Plunge Pool', 'Desert Access', 'Full Staff', 'Outdoor Kitchen', 'WiFi'], '#2a1810', true, true, '{"rooms": 6, "bathrooms": 4, "ceiling": "3.8m", "power": "3x 32A + generator", "parking": "10 vehicles"}', array['https://images.unsplash.com/photo-1509233725247-49e657c54213?w=1800&q=85&auto=format&fit=crop', 'https://images.unsplash.com/photo-1547471080-7cc2caa01a7e?w=1800&q=85&auto=format&fit=crop', 'https://images.unsplash.com/photo-1473445361085-b9a07f55efb2?w=1800&q=85&auto=format&fit=crop', 'https://images.unsplash.com/photo-1519608487953-e999c86e7455?w=1800&q=85&auto=format&fit=crop'], true),
('Villa Yasmine', 'Hammamet', 'Tunisia', 'villa', 'A sun-bleached garden estate on the Cap Bon coast — mosaic pool, orange-blossom courtyards, and the warm Hammamet light that has seduced cinematographers for decades.', 890, '€', 4.9, 73, 490, 55, 36.395, 10.621, array['Photo Shoot', 'Events', 'Brand Campaigns'], array['Pool', 'Sea View', 'Garden', 'Full Staff', 'WiFi', 'Parking'], '#091a05', true, true, '{"rooms": 7, "bathrooms": 5, "ceiling": "3.1m", "power": "3x 32A", "parking": "12 vehicles"}', array['https://images.unsplash.com/photo-1564013799919-ab600027ffc6?w=1800&q=85&auto=format&fit=crop', 'https://images.unsplash.com/photo-1575429198097-0414ec08e8cd?w=1800&q=85&auto=format&fit=crop', 'https://images.unsplash.com/photo-1512917774080-9991f1c4c750?w=1800&q=85&auto=format&fit=crop'], true),
('Riad Carthage', 'Carthage', 'Tunisia', 'mansion', 'A grand colonial residence overlooking the ancient Punic ruins and the Gulf of Tunis. Marble halls, a cedar-panelled library, and terraced gardens that descend to the sea.', 1280, '€', 5.0, 29, 720, 90, 36.852, 10.331, array['Film Production', 'Photo Shoot', 'Events'], array['Sea View', 'Pool', 'Library', 'Full Staff', 'Generator', 'Parking 20+'], '#100a1f', true, false, '{"rooms": 14, "bathrooms": 8, "ceiling": "4.2m", "power": "3x 63A", "parking": "20 vehicles"}', array['https://images.unsplash.com/photo-1520250497591-112f2f40a3f4?w=1800&q=85&auto=format&fit=crop', 'https://images.unsplash.com/photo-1561049933-c8fbef47b329?w=1800&q=85&auto=format&fit=crop', 'https://images.unsplash.com/photo-1571003123894-1f0594d2b5d9?w=1800&q=85&auto=format&fit=crop'], true),
('Nabeul Faïence Studio', 'Nabeul', 'Tunisia', 'studio', 'A converted artisan workshop in the pottery capital of Tunisia — hand-painted tile vaults, cobalt-washed walls, and a rear courtyard of extraordinary light quality.', 310, '€', 4.8, 91, 240, 25, 36.451, 10.731, array['Photo Shoot', 'Brand Campaigns', 'Influencer'], array['Courtyard', 'Natural Light', 'WiFi', 'Wardrobe Room', 'Zellige Walls'], '#0a0f1f', true, true, '{"rooms": 4, "bathrooms": 2, "ceiling": "4.2m", "power": "2x 32A", "parking": "6 vehicles"}', array['https://images.unsplash.com/photo-1558618666-fcd25c85cd64?w=1800&q=85&auto=format&fit=crop', 'https://images.unsplash.com/photo-1598828073074-bd1d0c8bd2c1?w=1800&q=85&auto=format&fit=crop'], true),
('Sousse Ribat Loft', 'Sousse', 'Tunisia', 'loft', 'Carved into the walls of a 9th-century ribat fortress — stone vaults, arrow-slit windows, and a medina panorama that no set builder could replicate. History as backdrop.', 460, '€', 4.7, 64, 360, 40, 35.826, 10.639, array['Film Production', 'Photo Shoot', 'Events'], array['Historic Vaults', 'Medina View', 'Generator', 'WiFi', 'Parking'], '#1a1005', true, false, '{"rooms": 5, "bathrooms": 3, "ceiling": "5.0m", "power": "3x 32A", "parking": "8 vehicles"}', array['https://images.unsplash.com/photo-1523580846011-d3a5bc25702b?w=1800&q=85&auto=format&fit=crop', 'https://images.unsplash.com/photo-1533050487297-09b450131914?w=1800&q=85&auto=format&fit=crop'], true);
